const ICON_BY_CATEGORY = {
  Income: BagRupeeIcon,
  Food: ForkKnifeIcon,
  Transport: CarTaxiIcon,
  Entertainment: SongRecommendationIcon,
  Bills: ReceiptIcon,
  Education: QualityEducationIcon,
  Health: HealthIcon,
  Shopping: ShoppingBasketIcon,
  Other: ShippingBoxIcon,
}

export default function CategoryIcon({ name, className = 'w-3.5 h-3.5', title }) {
  const Icon = ICON_BY_CATEGORY[name] || ShippingBoxIcon

  return (
    <span className="inline-flex items-center justify-center" title={title || name} aria-hidden="true">
      <Icon className={className} />
    </span>
  )
}
